import React from "react";
import { useParams } from "react-router-dom";

import PlaceList from "../components/PlaceList";

const DUMMY_PLACES = [
    {
        id: 'p1',
        title: 'Dubai – Stad van records en glitter',
        description: 'One of the most famous sky scrapers in the worls!',
        imageUrl: 'https://travelizi.nl/sites/default/files/inline-images/Atlantis%2C%20The%20Palm%2C%20Dubai-faisal-manga-4NeuZU-ynnw-unsplash.jpg',
        address: 'Midtown Manhattan, Fifth Avenue at 34th Street, New York City.',
        location: {
            lat: 40.7484405,
            lng: -73.9878584
        },
        creator: 'u1'
    },
    {
        id: 'p2',
        title: 'Empire State Building',
        description: 'One of the most famous sky scrapers in the worls!',
        imageUrl: 'https://cdn.britannica.com/73/114973-050-2DC46083/Midtown-Manhattan-Empire-State-Building-New-York.jpg',
        address: 'Midtown Manhattan, Fifth Avenue at 34th Street, New York City.',
        location: {
            lat: 40.7484405,
            lng: -73.9878584
        },
        creator: 'u2'
    },
]
    const UserPlaces = () => {
       const userId = useParams().userId;
       const loadedPlaces = DUMMY_PLACES.filter(place => place.creator === userId);
    return <PlaceList items= {loadedPlaces} />;
};

export default UserPlaces;
